local function extract_soap_data(parser)
    local soap_data = {}
    
    -- Extract SOAP envelope
    local envelope = parser[1]
    if envelope and envelope.tag == "Envelope" then
        soap_data.envelope = {}
        for _, child in ipairs(envelope) do
            if type(child) == "table" and child.tag then
                soap_data.envelope[child.tag] = child
            end
        end
    end
    
    -- Extract body data
    local body = parser[1] and parser[1][1]
    if body and body.tag == "Body" then
        soap_data.body = {}
        for _, child in ipairs(body) do
            if type(child) == "table" and child.tag then
                soap_data.body[child.tag] = child
            end
        end
    end
    
    return soap_data
end

